    var(--grad-stop-3),
    var(--grad-stop-4),
    var(--grad-stop-5) calc(100% - (var(--min-hit-dimension-aaa) / 2) - 8px),
    white
  );

  box-sizing: border-box;
  display: flex;

  /* gives input more room on left and right ends to be hit more successfully */
  padding: 0 calc(var(--min-hit-dimension-aaa) / 2);
  border: var(--border-width-thin) solid var(--color-border-default);
  border-left: none;
  border-right: none;
  align-items: center;
  background: var(--default-background);

  &:hover {
    box-shadow: var(--shadow-sm);
  }

  input[type='range'] {
    -webkit-appearance: none;
    appearance: none;
    flex-grow: 1;
    width: 100%;
    height: 46px;
    min-height: var(--min-hit-dimension-aaa);
    margin: 0;
    background: transparent;
    cursor: pointer;

    &::-webkit-slider-runnable-track {
      height: 4px;
      border-radius: 99px;
      background: transparent;
    }

    &::-webkit-slider-thumb {
      -webkit-appearance: none;
      width: 1.375rem;
      height: 1.375rem;
      margin-top: calc((1.375rem - 4px) / -2);
      border-radius: 50%;
      background: #ffffff;
      border: 2px solid rgba(0, 0, 0, 0.18);
      box-shadow: 0 2px 6px rgba(0, 0, 0, 0.4), 0 0 0 1.5px rgba(0, 0, 0, 0.12);
      cursor: pointer;
      transition: transform 0.1s ease, box-shadow 0.1s ease;
    }

    &:hover:not(:disabled)::-webkit-slider-thumb {
      transform: scale(1.1);
      box-shadow: 0 2px 6px rgba(0, 0, 0, 0.28);
    }

    &:focus {
      outline: none;
    }

    &:focus-visible::-webkit-slider-thumb {
      outline: var(--focus-ring-width) solid var(--color-focus);
      outline-offset: var(--focus-ring-offset);
    }
  }

  .special-case {
    display: flex;
    flex-grow: 1;
    height: 46px;
    min-height: var(--min-hit-dimension-aaa);
    align-items: center;

    /* TODO: what do custom input text need to be? <p>? */
    div {
      font-family: var(--font-family-mono);
      font-size: var(--font-size-base);
      font-weight: 400;
    }
  }
}

.dev-overlay {
  display: none;
  position: absolute;
  gap: 1rem;
  right: 0;
  bottom: 0;

  &.active {
    display: flex;
  }

  .light-variant-chip {
    border-radius: 100%;
    width: 15px;
    height: 15px;
    border: 15px solid var(--gray-900);
  }
}

